+/// Comptime lookup table for escape sequences (eliminates switch!)
+const ESCAPE_SEQUENCES: [256][]const u8 = blk: {
+    var table: [256][]const u8 = [_][]const u8{""} ** 256;
+    table['"'] = "\\\"";
+    table['\\'] = "\\\\";
+    table['\x08'] = "\\b";
+    table['\x0C'] = "\\f";
+    table['\n'] = "\\n";
+    table['\r'] = "\\r";
+    table['\t'] = "\\t";
+    break :blk table;
+};
+
